// 读取当前 Writer 文档的完整文本内容
var doc = Application.ActiveDocument;
var content = '';
for (var i = 0; i < doc.Sections.Count; i++) {
  var section = doc.Sections.Item(i + 1);
  for (var j = 0; j < section.Paragraphs.Count; j++) {
    var para = section.Paragraphs.Item(j + 1);
    content += para.Range.Text;
  }
}
return content.substring(0, 5000);

// 读取当前 Writer 文档的完整文本内容（修正API调用方式）
var doc = Application.ActiveDocument;
var content = '';
if (doc && doc.Sections) {
  for (var i = 0; i < doc.Sections.Count; i++) {
    var section = doc.Sections.Item(i + 1);
    if (section && section.Paragraphs) {
      for (var j = 0; j < section.Paragraphs.Count; j++) {
        var para = section.Paragraphs.Item(j + 1);
        if (para && para.Range) {
          content += para.Range.Text;
        }
      }
    }
  }
}
return content.substring(0, 5000);

// 尝试通过 Range 直接获取文档全文
var doc = Application.ActiveDocument;
if (doc && doc.Range) {
  return doc.Range.Text.substring(0, 5000);
}
return "无法读取文档内容";
